export default function ImportV2Page() {
  const [status, setStatus] = useState("")
  const [done, setDone] = useState(false)

  async function handleImport() {
    setStatus("Köhnə məlumatlar silinir...")
    
    await supabase.from("bookings").delete().neq("id", "00000000-0000-0000-0000-000000000000")
    await supabase.from("payments").delete().neq("id", "00000000-0000-0000-0000-000000000000")
    await supabase.from("client_balances").delete().neq("id", "00000000-0000-0000-0000-000000000000")
    await supabase.from("client_balance_transactions").delete().neq("id", "00000000-0000-0000-0000-000000000000")

    setStatus("Sifarişlər idxal edilir...")
    let total = 0
    for (let i = 0; i < BOOKINGS.length; i++) {
      const { error } = await supabase.from("bookings").insert(BOOKINGS[i])
      if (error) { setStatus("Xəta: " + error.message); return }
      total += BOOKINGS[i].length
      setStatus(`Sifarişlər: ${total} / 1179`)
    }

    setStatus("Balanslar idxal edilir...")
    let btotal = 0
    for (let i = 0; i < BALANCES.length; i++) {
      const { error } = await supabase.from("client_balances").insert(BALANCES[i])
      if (error) { setStatus("Balans xətası: " + error.message); return }
      btotal += BALANCES[i].length
      setStatus(`Balanslar: ${btotal} / 87`)
    }

    setStatus("✅ Tamamlandı! 1179 sifariş + 87 balans idxal edildi.")
    setDone(true)
  }

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center p-6">
      <div className="bg-white rounded-2xl border border-gray-100 p-8 max-w-md w-full">
        <h1 className="text-xl font-bold text-gray-900 mb-2">Məlumat idxalı v2</h1>
        <p className="text-sm text-gray-500 mb-6">1179 sifariş + 87 müştəri balansı</p>
        {!done && (
          <button onClick={handleImport}
            className="w-full bg-red-500 text-white py-3 rounded-xl font-medium hover:bg-red-600">
            İdxal et
          </button>
        )}
        {status && (
          <p className="mt-4 text-sm text-gray-600 bg-gray-50 p-3 rounded-xl">{status}</p>
        )}
      </div>
    </div>
  )
}
